const input = $json;

const conversations = input.payload || [];

const inboxIdDesejado = Number($('Nicho').first().json.inbox_id);

const getTimestamp = (conv) => {
  return Number(
    conv.last_activity_at ||
    conv.updated_at ||
    conv.created_at ||
    0
  );
};

const ordenarMaisRecente = (lista) => {
  return [...lista].sort((a, b) => getTimestamp(b) - getTimestamp(a));
};

const conversasInbox = conversations.filter(conv => {
  return Number(conv.inbox_id) === inboxIdDesejado;
});

const conversasOpen = ordenarMaisRecente(
  conversasInbox.filter(conv => conv.status === 'open')
);

const conversasPending = ordenarMaisRecente(
  conversasInbox.filter(conv => conv.status === 'pending')
);

const conversasResolved = ordenarMaisRecente(
  conversasInbox.filter(conv => conv.status === 'resolved')
);

const conversasOutras = ordenarMaisRecente(
  conversasInbox.filter(conv =>
    !['open', 'pending', 'resolved'].includes(conv.status)
  )
);

const conversaSelecionada =
  conversasOpen[0] ||
  conversasPending[0] ||
  conversasResolved[0] ||
  conversasOutras[0] ||
  null;

const sourceId =
  conversaSelecionada?.messages?.[0]?.conversation?.contact_inbox?.source_id ||
  conversaSelecionada?.last_non_activity_message?.conversation?.contact_inbox?.source_id ||
  conversaSelecionada?.contact_inbox?.source_id ||
  $('Pega Contato').item.json.source_id ||
  null;

return [
  {
    json: {
      tem_conversa_inbox: !!conversaSelecionada,
      conversation_id: conversaSelecionada?.id || null,
      conversation_status: conversaSelecionada?.status || null,
      can_reply: conversaSelecionada?.can_reply ?? false,
      inbox_id: conversaSelecionada?.inbox_id || null,
      inbox_id_desejado: inboxIdDesejado,
      source_id: sourceId,
      precisa_criar_conversa: !conversaSelecionada,
      criterio_selecao: conversaSelecionada
        ? `conversa_${conversaSelecionada.status || 'sem_status'}_mais_recente`
        : 'nenhuma_conversa_encontrada',
      total_conversas_inbox: conversasInbox.length,
      total_open: conversasOpen.length,
      total_pending: conversasPending.length,
      total_resolved: conversasResolved.length,
      conversa: conversaSelecionada
    }
  }
];

