const dadosEnvio = $('Dados Envio').first().json;
const temContato = $('Criar Contato?').item.json;
const template = dadosEnvio.template || {};
const bodyParams = template.body_params || {};
const inboxIdDesejado = Number($('Nicho').first().json.inbox_id);

let contentRenderizado = String(template.content || '');

for (const [key, value] of Object.entries(bodyParams)) {
  const regex = new RegExp(`{{\\s*${key}\\s*}}`, 'g');
  contentRenderizado = contentRenderizado.replace(regex, String(value ?? ''));
}

return [
  {
    json: {
      account_id: 1,
      conversation_id: $json?.conversation_id || $json?.id || null,
      inbox_id: $json?.inbox_id || inboxIdDesejado,
      inbox_id_desejado: inboxIdDesejado,
      source_id: $json?.source_id || $json?.payload?.contact_inbox?.source_id || null,
      contact_id: $json?.contact_id || $json?.payload?.contact?.id || $json?.meta?.sender?.id || temContato?.contact_id || null,
      nicho: dadosEnvio.nicho || null,

      template: {
        nome: template.nome || null,
        media_url: template.media_url || null,
        media_name: template.media_name || null,
        content: template.content || null,
        body_params: bodyParams,
        content_renderizado: contentRenderizado
      }
    }
  }
];

